'use client';

import { zodResolver } from '@hookform/resolvers/zod';
import { useMutation } from '@tanstack/react-query';
import { Loader2 } from 'lucide-react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { useEffect, useState } from 'react';
import { useForm } from 'react-hook-form';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Button } from '@/components/ui/button';
import { Field, FieldDescription, FieldError, FieldGroup, FieldLabel } from '@/components/ui/field';
import { Input } from '@/components/ui/input';
import { ROUTES } from '@/constants/routes';
import { getApiErrorMessage } from '@/lib/api/unwrap';
import { useAuth } from '../hooks/use-auth';
import { otpSchema, type OtpFormValues } from '../schemas/otp.schema';
import { otpSessionStorage } from '../utils/otp-session-storage';

export function OtpForm() {
  const router = useRouter();
  const { verifyOtp, resendOtp } = useAuth();
  const [session, setSession] = useState(() => otpSessionStorage.get());

  const form = useForm<OtpFormValues>({
    resolver: zodResolver(otpSchema),
    defaultValues: { code: '' },
  });

  useEffect(() => {
    if (!session) {
      router.replace(ROUTES.login);
    }
  }, [session, router]);

  const verifyMutation = useMutation({
    mutationFn: (code: string) =>
      verifyOtp({
        otpSessionId: session!.otpSessionId,
        code,
      }),
    onSuccess: () => {
      router.replace(ROUTES.dashboard);
    },
  });

  const resendMutation = useMutation({
    mutationFn: () => resendOtp(session!.otpSessionId),
    onSuccess: () => {
      setSession(otpSessionStorage.get());
    },
  });

  const onSubmit = form.handleSubmit((values) => {
    verifyMutation.mutate(values.code);
  });

  if (!session) {
    return null;
  }

  const errorMessage = verifyMutation.error
    ? getApiErrorMessage(verifyMutation.error, 'Verification failed. Please try again.')
    : null;

  const expiresLabel = session.expiresAt
    ? new Date(session.expiresAt).toLocaleTimeString()
    : undefined;

  return (
    <form onSubmit={onSubmit} className="space-y-4">
      <FieldGroup>
        <Field data-invalid={!!form.formState.errors.code}>
          <FieldLabel htmlFor="code">Verification code</FieldLabel>
          <FieldDescription>
            {session.email ? (
              <>Enter the 6-digit code sent for {session.email}.</>
            ) : (
              <>Enter the 6-digit code from your authenticator or email.</>
            )}
            {expiresLabel ? <> Expires at {expiresLabel}.</> : null}
          </FieldDescription>
          <Input
            id="code"
            inputMode="numeric"
            autoComplete="one-time-code"
            maxLength={6}
            placeholder="000000"
            className="text-center text-lg tracking-[0.3em]"
            aria-invalid={!!form.formState.errors.code}
            {...form.register('code')}
          />
          <FieldError errors={[form.formState.errors.code]} />
        </Field>
      </FieldGroup>

      {errorMessage ? (
        <Alert variant="destructive">
          <AlertDescription>{errorMessage}</AlertDescription>
        </Alert>
      ) : null}

      <Button type="submit" className="w-full" disabled={verifyMutation.isPending}>
        {verifyMutation.isPending ? (
          <>
            <Loader2 className="size-4 animate-spin" />
            Verifying…
          </>
        ) : (
          'Verify and continue'
        )}
      </Button>

      <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
        <Button
          type="button"
          variant="outline"
          size="sm"
          disabled={resendMutation.isPending}
          onClick={() => resendMutation.mutate()}
        >
          {resendMutation.isPending ? 'Sending…' : 'Resend code'}
        </Button>
        <Button render={<Link href={ROUTES.login} />} variant="ghost" size="sm" type="button">
          Back to login
        </Button>
      </div>
    </form>
  );
}
